<template>
<div class="padding-t_10" id="reportstabsdata">
    <div class="left-menu-tab new_tab">
        <div class="col-md-12 p-0">
            <div class="theme-primary partition">
                <span class="p-name text-white">{{ $t("ApprovalReport") }}</span>
            </div>
        </div>
        <div class="pt-2 mb-1 w-100 d-none d-lg-block">
            <div class="input-group customsearchbox">
                <input type="text" maxlength="50" :placeholder="Search" class="form-control searchcustomfilter border-right-0" autocomplete="off" v-model="searchQuery" />
                <div class="input-group-append">
                    <span class="input-group-text bg-transparent bg-white border-left-0"><i class="fa fa-search"></i></span>
                </div>
            </div>
        </div>
        <div class="mt-2" id="divscrollsetuptabs" style="max-height: 700px">
            <ul class="nav nav-pills flex-column left-tab responivecustomtab lefttabiconfix lefttabflexible" id="upper" role="tablist">
                <li v-for="(tab, index) in filteredTabs" :key="index">
                    <a class="nav-link left-menu" :data-toggle="'#' + tab.id" :class="{ active: activeKey === tab.index }" @click="activateTab(tab.index)">
                        <i :class="tab.icon" aria-hidden="true"></i>&nbsp;
                        {{ $t(tab.name) }}
                    </a>
                </li>
            </ul>
        </div>
    </div>
    <!-- right-content here -->
    <div class="right-content">
        <div class="col-md-12 p-0">
            <div class="theme-primary partition p-actions-expand" style="overflow: visible">
                <span class="p-name text-white" id="spnreporttext">{{
            this.$t(activeTabName)
          }}</span>
                <span class="p-actions float-right">
                    <a href="javascript:;" id="ancshowmorefilter" class="p-action-btn text-white" style="display: none" :title="$t('Show') + ' ' + $t('More') + ' ' + $t('Filter')"><i class="fa fa-filter" aria-hidden="true"></i><br />{{
                $t("Show")
              }}
                        {{ $t("More") }} {{ $t("Filter") }}</a>
                </span>
                <span id="showDaterange" style="display: none" class="p-actions float-right p-2">
                    <!-- @await Html.PartialAsync("~/Areas/BiReports/Views/Shared/DateRange.cshtml") -->
                </span>
                <span class="collapse-head-btns">
                    <a href="javascript:;" class="collapse-btns"><i class="fa fa-angle-up text-white"></i></a>
                </span>
            </div>
        </div>
        <div class="col-md-12 p-0">
            <div class="tab-content" id="myTabContent">
                <div class="expand-list">
                    <a href="javascript:;" class="expand-list-btn justify-content-center align-items-center">
                        <i class="icon-solid arrow-solid-left text-white" style="font-size: 9pt"></i>
                    </a>
                </div>
                <div id="NonRuleUsers" class="tab-pane" :class="{ 'active show': activeKey == 0 }" v-if="activeKey == 0">
                    <div v-if="tabAccess[0] === null" class="loading p-4 text-center">
                        {{ this.$t("PageLoadMsg") }}
                    </div>
                    <div v-else-if="tabAccess[0]">
                        <NonRuleUsers></NonRuleUsers>
                    </div>
                    <div v-else class="unauthorized-message p-4 text-center">
                        <p>{{ this.$t("UnauthorizedReport") }}</p>
                    </div>
                </div>
                <div id="UserWiseApprovalRuleInformation" class="tab-pane" :class="{ 'active show': activeKey == 1 }" v-if="activeKey == 1">
                    <div v-if="tabAccess[1] === null" class="loading p-4 text-center">
                        {{ this.$t("PageLoadMsg") }}
                    </div>
                    <div v-else-if="tabAccess[1]">
                        <UserWiseApprovalRuleInformation></UserWiseApprovalRuleInformation>
                    </div>
                    <div v-else class="unauthorized-message p-4 text-center">
                        <p>{{ this.$t("UnauthorizedReport") }}</p>
                    </div>
                </div>
            </div>
        </div>
    </div>
    <!-- right-content End here -->
</div>
</template>
<script>
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
    import UserWiseApprovalRuleInformation from "../ApprovalReport/UserWiseApprovalRuleInformation.vue";
    import NonRuleUsers from "../ApprovalReport/NonRuleUsers.vue";
    import DataService from "../../services/DataService"
export default {
    components: {
        NonRuleUsers,
        UserWiseApprovalRuleInformation,
    },
    data() {
        return {
            activeKey: 0,
            tabNames: [
                "NonRuleUsers",
                "User Wise ApprovalRule Information",
            ],
            searchQuery: "",
            tabAccess: [null, null],
        };
    },
    mounted() {
        this.activateTab(0);
    },
    computed: {
        filteredTabs() {
            if (!this.searchQuery) {
                return this.tabNames.map((name, index) => ({
                    name,
                    index,
                    id: name.replace(/\s+/g, ''),
                    icon: this.getTabIcon(name)
                }));
            }
            const query = this.searchQuery.toLowerCase();
            return this.tabNames
                .map((name, index) => ({
                    name,
                    index,
                    id: name.replace(/\s+/g, ''),
                    icon: this.getTabIcon(name)
                }))
                .filter(tab => this.$t(tab.name).toLowerCase().includes(query));
        },
        activeTabName() {
            return this.tabNames[this.activeKey];
        }
    },
    methods: {
        async GetPrivilege(param) {
            try {
                const response = await DataService.CheckPrivilege(param);
                // response.data is the boolean value
                console.log('Privilege response:', response);
                return response.data;
            } catch (error) {
                console.error('Error in GetPrivilege:', error);
                return false;
            }
        },
        async checkTabPrivilege(index, controller, action) {
            try {
                const param = `controller=${controller}&action=${action}`;
                const hasAccess = await this.GetPrivilege(param);
                return hasAccess;
            } catch (error) {
                console.error(`Error checking privilege for tab ${index}:`, error);
                return false;
            }
        },
        async activateTab(index) {
            this.activeKey = index;
            if (this.tabAccess[index] === null) {
                const controller = 'ApprovalReport'; 
                let action;
                if (index === 0) {
                    action = 'NonRuleUsers';
                } else if (index === 1) {
                    action = 'ApprovalRuleInformation';
                }
                const hasAccess = await this.checkTabPrivilege(index, controller, action);
                console.log(`Tab ${index} (${action}): hasAccess = ${hasAccess}`);
                this.$set(this.tabAccess, index, hasAccess);
            }
        },
        getTabIcon(name) {
            switch (name) {
                case "NonRuleUsers":
                    return "fa fa-users"; 
                case "User Wise ApprovalRule Information":
                    return "fa fa-cogs"; 
                default:
                    return "";
            }
        },
    }
}
</script>
<style scoped>
.p-actions-expand:before{
    display: none;;
}
.collapse-head-btns {
    display: none !important;
}
.unauthorized-message {
    color: #dc3545;
    background-color: #f8d7da;
    border: 1px solid #f5c6cb;
    border-radius: 4px;
}
.loading {
    color: #6c757d;
}
</style>